def extract_letters(cell):
    """提取单元格引用中的字母部分（列标识）"""
    if not isinstance(cell, str):
        return ''
    match = re.match(r'^[A-Za-z]+', cell)
    return match.group(0) if match else ''


def extract_numbers(cell):
    """提取单元格引用中的数字部分（行号）"""
    if not isinstance(cell, str):
        return 0
    letters = extract_letters(cell)
    number_part = cell[len(letters):]
    match = re.match(r'\d+', number_part)
    return int(match.group(0)) if match else 0


